//! Barrel (`index.ts`) generator that re-exports all generated contract files.

use abi_typegen_config::{Config, Target};

/// Generates `index.ts` re-exporting all generated files.
/// `contract_names` is the list of generated contract names (e.g. ["ERC20", "Vault"]).
pub fn render_barrel(contract_names: &[String], config: &Config) -> String {
    let mut out = String::new();
    out.push_str("// Auto-generated by abi-typegen. Do not edit manually.\n\n");

    for name in contract_names {
        if config.target.emits_typescript_abi() {
            out.push_str(&format!("export * from './{}.abi.js';\n", name));
        }
        if matches!(config.target, Target::Zod) {
            out.push_str(&format!("export * from './{}.zod.js';\n", name));
        }
        if config.wrappers {
            if let Some(suffix) = config.target.wrapper_module_suffix() {
                out.push_str(&format!("export * from './{}.{}.js';\n", name, suffix));
            }
        }
    }

    out
}

#[cfg(test)]
mod tests {
    use super::*;
    use abi_typegen_config::Config;

    fn default_config() -> Config {
        Config::from_toml_str("").unwrap()
    }

    fn viem_config() -> Config {
        Config::from_toml_str("[abi-typegen]\ntarget = \"viem\"\n").unwrap()
    }

    fn ethers_config() -> Config {
        Config::from_toml_str("[abi-typegen]\ntarget = \"ethers\"\n").unwrap()
    }

    fn zod_config() -> Config {
        Config::from_toml_str("[abi-typegen]\ntarget = \"zod\"\n").unwrap()
    }

    fn python_config() -> Config {
        Config::from_toml_str("[abi-typegen]\ntarget = \"python\"\n").unwrap()
    }

    #[test]
    fn barrel_contains_abi_exports() {
        let names = vec!["ERC20".to_string(), "Vault".to_string()];
        let out = render_barrel(&names, &default_config());
        assert!(out.contains("export * from './ERC20.abi.js'"));
        assert!(out.contains("export * from './Vault.abi.js'"));
    }

    #[test]
    fn viem_target_only_viem() {
        let names = vec!["ERC20".to_string()];
        let out = render_barrel(&names, &viem_config());
        assert!(out.contains("export * from './ERC20.viem.js'"));
        assert!(!out.contains("ethers"));
    }

    #[test]
    fn ethers_target_only_ethers() {
        let names = vec!["ERC20".to_string()];
        let out = render_barrel(&names, &ethers_config());
        assert!(out.contains("export * from './ERC20.ethers.js'"));
        assert!(!out.contains("viem"));
    }

    #[test]
    fn empty_contracts_empty_barrel() {
        let out = render_barrel(&[], &default_config());
        assert!(out.starts_with("// Auto-generated"));
        assert_eq!(out.lines().count(), 2); // header line + blank line
    }

    #[test]
    fn no_wrappers_only_abi_exports() {
        let names = vec!["ERC20".to_string()];
        let mut cfg = default_config();
        cfg.wrappers = false;
        let out = render_barrel(&names, &cfg);
        assert!(out.contains("export * from './ERC20.abi.js'"));
        assert!(!out.contains("viem"));
        assert!(!out.contains("ethers"));
    }

    #[test]
    fn non_ts_target_has_no_broken_abi_exports() {
        let names = vec!["ERC20".to_string()];
        let out = render_barrel(&names, &python_config());
        assert!(!out.contains("abi.js"));
        assert!(!out.contains(".py"));
    }

    #[test]
    fn zod_target_exports_abi_and_schema_even_without_wrappers() {
        let names = vec!["ERC20".to_string()];
        let mut cfg = zod_config();
        cfg.wrappers = false;
        let out = render_barrel(&names, &cfg);
        assert!(out.contains("export * from './ERC20.abi.js'"));
        assert!(out.contains("export * from './ERC20.zod.js'"));
        assert!(!out.contains("viem"));
    }
}
